// Funções de tempo
const delayMs = (ms) => new Promise(resolve => setTimeout(resolve, ms));
const delayUs = (us) => {
    const start = process.hrtime.bigint();
    const target = start + BigInt(us * 1000);
    while (process.hrtime.bigint() < target) {} // Trava milimétrica
};

// Como temos 2 saídas no nó, usamos arrays para enviar mensagens
// node.send([ {mensagem Saida 1}, {mensagem Saida 2} ])

node.status({fill:"blue", shape:"dot", text:"Iniciando..."});

// Envolvemos numa função assíncrona auto-executável
(async function() {
    // Relé ON (Saída 1 = 1, Saída 2 = null)
    node.send([{ payload: 1 }, null]);
    await delayMs(1000);

    // Relé OFF
    node.send([{ payload: 0 }, null]);
    await delayMs(1000);

    node.status({fill:"red", shape:"dot", text:"Pulsando..."});

    // Envia os pulsos para o Transistor (Saída 2)
    for(let i = 0; i < pulsos; i++) {
        node.send([null, { payload: 1 }]); // Borda de subida
        delayUs(2000);

        node.send([null, { payload: 0 }]); // Borda de descida
        delayUs(2000);
    }

    // Finaliza garantindo tudo OFF
    await delayMs(100);
    node.send([{ payload: 0 }, { payload: 0 }]);

    node.status({fill:"green", shape:"dot", text:"Concluído"});
})();

return null; // O envio é feito dentro da função assíncrona
